UPDATE spells SET summary = 'Animate bones/corpse as undead servant ({@creature skeleton} or {@creature zombie}). Command within 60 feet as bonus action. Control 24 hours; recast to maintain.' WHERE slug = 'animate-dead';
UPDATE spells SET summary = 'Next hit deals {@damage 3d8} extra radiant damage. Target Con save or {@condition blinded} until spell ends. {@condition blinded}} creature repeats save at end of each turn.' WHERE slug = 'blinding-smite';
UPDATE spells SET summary = 'Roll {@dice d20} end of turn: 11+ vanish to Ethereal Plane. Return next turn within 10 feet. While Ethereal, see/hear Material Plane (60 feet). Only affect Ethereal creatures.' WHERE slug = 'blink';
UPDATE spells SET summary = 'Storm cloud (60-radius) appears. Lightning bolt deals {@damage 3d10} (Dex save half). Use action each turn. Outdoors in storm: +{@damage 1d10}.' WHERE slug = 'call-lightning';
UPDATE spells SET summary = 'Invisible sensor appears in familiar or obvious location. See or hear (action to switch). Duration: sensor stays. Luminous orb to {@sense truesight}.' WHERE slug = 'clairvoyance';
UPDATE spells SET summary = '5-foot fire sphere. Creatures ending turn within 5 feet: Dex save, {@damage 2d6} (half on success). Move 30 feet bonus action; ram does save damage.' WHERE slug = 'flaming-sphere';
UPDATE spells SET summary = '60-foot line of wind. Creatures: Str save or pushed 15 feet. Moving closer costs 2x movement. Disperses gas, extinguishes torches. Change direction as bonus action.' WHERE slug = 'gust-of-wind';
UPDATE spells SET summary = 'Nature spirit, 5-foot cube. Creatures entering/starting turn: restore {@dice 1d6} HP. Heals 1+spellcasting modifier times, then disappears. Move 30 feet bonus action.' WHERE slug = 'healing-spirit';
UPDATE spells SET summary = 'Metal object glows. Touch: {@damage 2d8} fire (repeat bonus action each turn). Creature holding: Con save or drop; disadvantage on attacks/checks until next turn.' WHERE slug = 'heat-metal';
UPDATE spells SET summary = 'Unlock one mundane lock or stuck object. Suppresses {@spell arcane lock} for 10 minutes. Creates loud knock audible 300 feet away.' WHERE slug = 'knock';
UPDATE spells SET summary = 'Target rises 20 feet (max 500 lbs). Unwilling: Con save. Move via pushing fixed objects. Alter height 20 feet per turn. Floats down when spell ends.' WHERE slug = 'levitate';
UPDATE spells SET summary = 'Sense direction to familiar object within 1,000 feet (or its movement). Can''t locate through lead.' WHERE slug = 'locate-object';
UPDATE spells SET summary = 'Implant message (≤25 words) in object. Triggers on condition, speaks in your voice. Can repeat or end after delivery.' WHERE slug = 'magic-mouth';
UPDATE spells SET summary = 'Earthen hand grasps creature (Str save). {@condition restrained}, {@damage 2d6} bludgeoning. Crush: {@damage 2d6} save half. {@condition restrained}} escape with Str check.' WHERE slug = 'maximilian's-earthen-grasp';
UPDATE spells SET summary = 'Three illusory duplicates. Attacks target duplicate (roll {@dice d20}: 3 dup=6+, 2=8+, 1=11+). Duplicate AC: 10+Dex. Destroyed by hits only.' WHERE slug = 'mirror-image';
UPDATE spells SET summary = '5-foot-radius light cylinder. Entering/starting turn: {@damage 2d10} radiant (Con save half). Shapechangers disadvantage; revert if fail. Move up to 60 feet.' WHERE slug = 'moonbeam';
UPDATE spells SET summary = 'False Aura: appear magical/nonmagical or change school. Mask: appear as different creature type. Lasts duration (permanent if cast daily 30 days).' WHERE slug = 'nystul's-magic-aura';
UPDATE spells SET summary = 'Target''s mind creates illusion (Int save). Believes real; can take damage ({@damage 1d6} psychic/turn). Investigation to disbelieve.' WHERE slug = 'phantasmal-force';
UPDATE spells SET summary = 'Extinguish flame. Fireworks: {@condition blinded}} creatures 10ft (Con save). Smoke: 20ft obscured area lasts 1 minute.' WHERE slug = 'pyrotechnics';
UPDATE spells SET summary = 'Rope hangs perpendicular. Invisible entrance to extradimensional space (holds 8 Medium/smaller). Pull rope inside, hide from attacks/spells.' WHERE slug = 'rope-trick';
UPDATE spells SET summary = '{@damage 2d8} psychic sword. Advantage in dim light. Finesse, light, thrown.' WHERE slug = 'shadow-blade';
UPDATE spells SET summary = 'Loud ringing at point. Creatures within 10 feet: {@damage 3d8} thunder (Con save half). Inorganic creatures disadvantage.' WHERE slug = 'shatter';
UPDATE spells SET summary = '20-foot radius becomes difficult terrain with spikes. Moving: {@damage 2d4} piercing per 5 feet traveled. Perception check to spot.' WHERE slug = 'spike-growth';
UPDATE spells SET summary = 'Floating weapon appears. Melee spell attack: {@damage 1d8} force + spellcasting mod. Move up to 20 feet, repeat attack as bonus action.' WHERE slug = 'spiritual-weapon';
UPDATE spells SET summary = 'Suggest action to creature (Wis save). Pursued if failed; ends when complete or duration expires. Set conditional trigger. Ends if damage.' WHERE slug = 'suggestion';
UPDATE spells SET summary = 'Summon {@creature Bestial Spirit|TCE}} (Air/Land/Water environment). Ally shares initiative, obeys commands. Disappears at 0 HP or end.' WHERE slug = 'summon-beast';
UPDATE spells SET summary = 'Willing creature gains +1 AC, saves, all damage resistance. You take same damage. Ends if either 60+ feet apart or 0 HP.' WHERE slug = 'warding-bond';
UPDATE spells SET summary = '10-foot wind radius around you. {@condition deafens}} creatures. Extinguishes unprotected flames. Difficult terrain for others. Ranged attacks disadvantage.' WHERE slug = 'warding-wind';
UPDATE spells SET summary = '20-foot webbing cube. Difficult terrain, lightly obscured. Creatures: Dex save or {@condition restrained}}. Flammable; 5-foot burns in round ({@damage 2d4}).' WHERE slug = 'web';
UPDATE spells SET summary = '15-foot-radius sphere. Creatures: Cha save or can''t deliberately lie. Aware of spell; can be evasive but truthful.' WHERE slug = 'zone-of-truth';
